// // This module compares two 64-bit inputs and outputs 0 if the first input is greater than the second input.
module comparator_64bit(
    input [63:0] a,
    input [63:0] b,
    output reg gt
);
    always @(*) begin
        if (a > b)
            gt = 1;
        else
            gt = 0;
    end
endmodule
